// Command openapiversion sets the info.version field of an OpenAPI YAML
// document.
//
// The config OpenAPI spec is generated by protoc-gen-connect-openapi, which
// does not emit info.version, so pkg/grpc/protoc.bash injects it from the
// current `git describe` tag. This command performs that injection
// idempotently: it removes any version key already present under info: before
// inserting the requested one, so re-running never produces a duplicate
// "version" key (which is invalid YAML and fails the check-yaml pre-commit
// hook).
//
// It rewrites the file line by line rather than round-tripping through a YAML
// marshaller so the generated document's formatting is preserved.
package main

import (
	"bytes"
	"flag"
	"fmt"
	"os"
	"strings"
)

func main() {
	version := flag.String("version", "", "value to set for info.version")
	file := flag.String("file", "", "path to the OpenAPI YAML document to modify")
	flag.Parse()

	if *version == "" || *file == "" {
		flag.Usage()
		os.Exit(2)
	}

	if err := run(*file, *version); err != nil {
		fmt.Fprintf(os.Stderr, "openapiversion: %v\n", err)
		os.Exit(1)
	}
}

func run(path, version string) error {
	info, err := os.Stat(path)
	if err != nil {
		return err
	}
	original, err := os.ReadFile(path)
	if err != nil {
		return err
	}
	updated := setInfoVersion(original, version)
	if bytes.Equal(original, updated) {
		return nil
	}
	return os.WriteFile(path, updated, info.Mode().Perm())
}

// setInfoVersion sets version as the first field of the top-level info block,
// replacing any version key already present in that block. If the document has
// no top-level info block it is returned unchanged.
func setInfoVersion(content []byte, version string) []byte {
	lines := strings.Split(string(content), "\n")
	out := make([]string, 0, len(lines)+1)
	inInfo := false
	for _, line := range lines {
		switch {
		case isTopLevelKey(line, "info"):
			out = append(out, line, "  version: "+version)
			inInfo = true
			continue
		case inInfo && strings.HasPrefix(line, "  version:"):
			// Drop any version already under info: so re-runs never duplicate it.
			continue
		case isTopLevelLine(line):
			inInfo = false
		}
		out = append(out, line)
	}
	return []byte(strings.Join(out, "\n"))
}

// isTopLevelKey reports whether line is the unindented YAML key "<key>:", with
// only trailing whitespace allowed after the colon.
func isTopLevelKey(line, key string) bool {
	return strings.TrimRight(line, " \t") == key+":"
}

// isTopLevelLine reports whether line starts a new unindented (top-level) node.
func isTopLevelLine(line string) bool {
	return len(line) > 0 && line[0] != ' ' && line[0] != '\t'
}
